func runDemo(args []string) error {
	fs := flag.NewFlagSet("demo", flag.ContinueOnError)
	fs.SetOutput(os.Stderr)
	configPath := fs.String("config", "", "optional broker config JSON file")
	if err := fs.Parse(args); err != nil {
		return commandError{message: err.Error(), code: 2}
	}
	repoRoot, err := findRepoRoot()
	if err != nil {
		return err
	}
	tempRoot, err := os.MkdirTemp("", "local-ai-broker-demo.")
	if err != nil {
		return err
	}
	defer os.RemoveAll(tempRoot)

	listenAddr, err := pickFreeLoopbackAddr()
	if err != nil {
		return err
	}
	envMap := defaultBrokerEnv(repoRoot, "local")
	envMap["BROKER_LISTEN_ADDR"] = listenAddr
	envMap["BROKER_JOB_STORE_PATH"] = filepath.Join(tempRoot, "jobs.json")
	envMap["BROKER_RUN_ROOT_PATH"] = filepath.Join(tempRoot, "runs")
	envMap["BROKER_AUDIT_LOG_PATH"] = filepath.Join(tempRoot, "audit.jsonl")
	if *configPath != "" {
		loaded, err := loadBootstrapConfig(repoRoot, *configPath)
		if err != nil {
			return err
		}
		for k, v := range loaded {
			envMap[k] = v
		}
		envMap["BROKER_LISTEN_ADDR"] = listenAddr
		envMap["BROKER_JOB_STORE_PATH"] = filepath.Join(tempRoot, "jobs.json")
		envMap["BROKER_RUN_ROOT_PATH"] = filepath.Join(tempRoot, "runs")
		envMap["BROKER_AUDIT_LOG_PATH"] = filepath.Join(tempRoot, "audit.jsonl")
	}
	if envMap["BROKER_BACKEND"] != "local" {
		return commandError{message: "demo currently supports local backend configs only", code: 2}
	}

	inputPath := filepath.Join(tempRoot, "demo.txt")
	if err := os.WriteFile(inputPath, []byte("Local AI Broker demo document.\n- one\n- two\n"), 0o644); err != nil {
		return err
	}

	cmd, stderrBuf, err := startBrokerServerProcess(repoRoot, envMap)
	if err != nil {
		return err
	}
	defer stopProcess(cmd)

	baseURL := "http://" + listenAddr
	if err := waitForHealthz(baseURL, 10*time.Second); err != nil {
		if stderrText := strings.TrimSpace(stderrBuf.String()); stderrText != "" {
			return fmt.Errorf("%w: %s", err, stderrText)
		}
		return err
	}

	jobID, err := submitDemoJob(baseURL, inputPath)
	if err != nil {
		return err
	}
	result, err := waitForResult(baseURL, jobID, 15*time.Second)
	if err != nil {
		return err
	}
	fmt.Printf("Demo job succeeded: %s\n", jobID)
	fmt.Println(result)
	return nil
}

func NormalizeTaskParams(taskParams map[string]any, payload map[string]any, taskType string) map[string]any {
	out := make(map[string]any, len(taskParams)+2)
	for k, v := range taskParams {
		out[k] = v
	}
	if value, ok := payload["query"]; ok {
		if text, ok := value.(string); ok && strings.TrimSpace(text) != "" {
			out["query"] = text
		}
	}
	if value, ok := payload["problem"]; ok {
		if text, ok := value.(string); ok && strings.TrimSpace(text) != "" {
			out["problem"] = text
		}
	}
	if value, ok := payload["retrieval_strategies"]; ok {
		if strategies, ok := value.([]any); ok && len(strategies) > 0 {
			out["retrieval_strategies"] = strategies
		}
	}
	if taskType == "inspect_repo" {
		mode := "auto"
		if value, ok := payload["mode"].(string); ok && strings.TrimSpace(value) != "" {
			mode = strings.ToLower(strings.TrimSpace(value))
		} else if value, ok := out["mode"].(string); ok && strings.TrimSpace(value) != "" {
			mode = strings.ToLower(strings.TrimSpace(value))
		}
		out["mode"] = mode
		if value, ok := payload["include_full_trace"].(bool); ok {
			out["include_full_trace"] = value
		}
	}
	if taskType == "debug_with_local_context" {
		if _, ok := out["problem"]; !ok {
			if text, ok := payload["problem"].(string); ok {
				out["problem"] = text
			}
		}
	}
	return out
}

// ValidateSubmitRequest enforces task contracts for both task-specific aliases
// and the generic job endpoint. Keeping this validation below the transport
// layer prevents callers from bypassing inspect_repo's answer-quality contract.

func directWorkerPath(repoRoot, localScriptPath, taskType string) (string, bool) {
	base := filepath.Base(strings.TrimSpace(localScriptPath))
	if base != "broker_worker.sh" && base != "broker_worker.slurm" {
		return "", false
	}
	var relative string
	switch strings.TrimSpace(taskType) {
	case "document_summary":
		relative = filepath.Join("workers", "document-summary", "main.py")
	case "log_analysis":
		relative = filepath.Join("workers", "log-analysis", "main.py")
	case "repo_summary":
		relative = filepath.Join("workers", "repo-summary", "main.py")
	case "inspect_repo":
		relative = filepath.Join("workers", "rag-compression", "inspect_repo_worker.py")
	case "rag_compress", "debug_with_local_context", "summarize_logs", "propose_patch":
		relative = filepath.Join("workers", "rag-compression", "main.py")
	default:
		return "", false
	}
	path := filepath.Join(repoRoot, relative)
	if _, err := os.Stat(path); err != nil {
		return "", false
	}
	return path, true
}

